import re

def count_branches(code_snippet):
    """More accurate branch counting"""
    branches = 0

    # Match patterns (each is a branch point)
    branches += len(re.findall(r'\bif\s+', code_snippet))  # if statements
    branches += len(re.findall(r'\belse\s+', code_snippet))  # else branches
    branches += len(re.findall(r'=>', code_snippet))  # match arms
    branches += len(re.findall(r'\|\|', code_snippet))  # or operators
    branches += len(re.findall(r'&&', code_snippet))  # and operators
    branches += len(re.findall(r'\?', code_snippet))  # try operators
    branches += len(re.findall(r'\.filter\(', code_snippet))  # filter closures
    branches += len(re.findall(r'\|[^|]*\|', code_snippet))  # closure parameters
    branches += len(re.findall(r'\bfor\s+', code_snippet))  # loops
    branches += len(re.findall(r'\bwhile\s+', code_snippet))  # while loops
    branches += len(re.findall(r'\.map\(', code_snippet))  # map closures
    branches += len(re.findall(r'\.and_then\(', code_snippet))  # and_then
    branches += len(re.findall(r'\.ok_or', code_snippet))  # ok_or conversions

    return branches

